#include <iostream>
using namespace std;
class Solution {
public:
    bool search(vector<int>& arr, int target) {
        int left = 0, right = arr.size()-1;
        while(left <= right) {
            int mid = left + (right-left)/2;
            if(arr[mid] == target) {
                return true;
            } else if(arr[mid] < target) {
                left = mid+1;
            } else {
                right = mid-1;
                if(mid == 0) right = 0; // Fix: correctly handle edge case when mid == 0
                if(arr[right] == target) {
                    return true;
                }
            }
        }
        return false;
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for(int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    int target;
    cin >> target;
    Solution solution;
    cout << boolalpha << solution.search(arr, target) << endl;
    return 0;
}
